CREATE TABLE q17_clients (
  client_id NUMBER,
  first_name VARCHAR2(30),
  last_name VARCHAR2(30),
  credit_limit NUMBER
);

INSERT INTO q17_clients VALUES (10, 'Ada', 'Lovelace', 500);

COMMIT;

questions.code:
DECLARE
  r q17_clients%ROWTYPE;
BEGIN
  SELECT * INTO r
  FROM q17_clients
  WHERE client_id = 10;

  r.credit_limit := r.credit_limit + 100;

  UPDATE q17_clients
  SET credit_limit = r.credit_limit
  WHERE client_id = r.client_id;

  DBMS_OUTPUT.PUT_LINE(r.first_name || ':' || SQL%ROWCOUNT || ':' || r.credit_limit);
END;
/

questions.setup_sql:
CREATE TABLE q17_students (
  student_id NUMBER,
  first_name VARCHAR2(30),
  last_name VARCHAR2(30),
  points NUMBER
);

INSERT INTO q17_students VALUES (1, 'Student', 'One', 80);
INSERT INTO q17_students VALUES (2, 'Student', 'Two', NULL);
INSERT INTO q17_students VALUES (3, 'Student', 'Three', 60);

COMMIT;

questions.code:
DECLARE
  v_points q17_students.points%TYPE;
BEGIN
  SELECT points INTO v_points
  FROM q17_students
  WHERE student_id = 2;

  IF v_points < 70 THEN
    DBMS_OUTPUT.PUT_LINE('LOW');
  ELSIF v_points IS NULL THEN
    DBMS_OUTPUT.PUT_LINE('MISSING');
  ELSE
    DBMS_OUTPUT.PUT_LINE('OK');
  END IF;
END;
/

questions.setup_sql:
CREATE TABLE q17_projects (
  project_id NUMBER,
  project_code VARCHAR2(20),
  status VARCHAR2(20)
);

INSERT INTO q17_projects VALUES (1, 'P1', 'NEW');
INSERT INTO q17_projects VALUES (2, 'P2', 'NEW');
INSERT INTO q17_projects VALUES (3, 'P3', 'DONE');

COMMIT;

questions.code:
DECLARE
  v_project_id q17_projects.project_id%TYPE;
BEGIN
  SELECT project_id INTO v_project_id
  FROM q17_projects
  WHERE status = 'NEW';

  DBMS_OUTPUT.PUT_LINE('ID=' || v_project_id);

EXCEPTION
  WHEN TOO_MANY_ROWS THEN
    DBMS_OUTPUT.PUT_LINE('MANY');
  WHEN NO_DATA_FOUND THEN
    DBMS_OUTPUT.PUT_LINE('NONE');
END;
/

