DECLARE
  v_total NUMBER;
BEGIN
  SELECT SUM(invoice_amount) INTO v_total
  FROM q17_invoices
  WHERE customer_code = 'C9';

  IF v_total IS NULL THEN
    DBMS_OUTPUT.PUT_LINE('NO SUM');
  ELSE
    DBMS_OUTPUT.PUT_LINE('TOTAL=' || v_total);
  END IF;

EXCEPTION
  WHEN NO_DATA_FOUND THEN
    DBMS_OUTPUT.PUT_LINE('NO DATA');
END;
/

