DECLARE
  TYPE t_vec IS VARRAY(3) OF NUMBER;
  v_vec t_vec := t_vec();
BEGIN
  v_vec.EXTEND(3);
  v_vec(1) := 10;
  v_vec(2) := 20;
  v_vec(3) := 30;
  v_vec.TRIM;
  DBMS_OUTPUT.PUT_LINE(v_vec.COUNT || ':' || v_vec.LIMIT);
END;
/

DECLARE
  CURSOR c IS SELECT 1 AS n FROM dual;
BEGIN
  OPEN c;
  OPEN c;
  CLOSE c;
  DBMS_OUTPUT.PUT_LINE('DONE');

EXCEPTION
  WHEN CURSOR_ALREADY_OPEN THEN
    DBMS_OUTPUT.PUT_LINE('OPEN');
END;
/

